impl russh::server::Handler for ConnectionHandler {
    async fn auth_password(
        &mut self,
        user: &str,
        password: &str,
    ) -> Result<Auth, Self::Error> {
        log::debug!("Password auth attempt for user '{}'", user);

        match self.authenticator.auth_password(user, password).await {
            AuthResult::Accept => {
                self.authenticated_user = Some(user.to_string());
                Ok(Auth::Accept)
            }
            AuthResult::Reject => {
                log::warn!("Password auth failed for user '{}'", user);
                Ok(Auth::Reject { 
                    proceed_with_methods: Some(MethodSet::PUBLICKEY) 
