//! List component example with theming

use lipgloss::{Style, ThemePreset, ThemeContext, ColorSlot, Border};
use std::sync::Arc;

fn main() {
    let ctx = Arc::new(ThemeContext::from_preset(ThemePreset::Nord));
    let theme = ctx.current();

    // List container style
    let list_style = Style::new()
        .border(Border::rounded())
        .border_foreground(theme.get(ColorSlot::Border))
        .padding(1)
        .width(40);

    // Item styles
    let item_style = Style::from_theme(&theme, ColorSlot::Foreground);
    let selected_style = Style::from_theme_colors(
        &theme,
        ColorSlot::Background,
        ColorSlot::Primary
    ).bold(true);

    // Render list
    let items = vec!["Option 1", "Option 2", "Option 3"];
    let selected = 1;

    let rendered_items: Vec<String> = items
        .iter()
        .enumerate()
        .map(|(i, item)| {
            if i == selected {
                selected_style.render(&format!("> {}", item))
            } else {
                item_style.render(&format!("  {}", item))
            }
        })
        .collect();

    println!("{}", list_style.render(&rendered_items.join("\n")));
}
