//! Demonstrates runtime theme switching

use lipgloss::{ThemedStyle, ThemeContext, ThemePreset, ColorSlot};
use std::sync::Arc;

fn main() {
    let ctx = Arc::new(ThemeContext::from_preset(ThemePreset::Dark));

    // Create styles that auto-update with theme changes
    let title = ThemedStyle::new(ctx.clone())
        .foreground(ColorSlot::Primary)
        .bold(true);

    let body = ThemedStyle::new(ctx.clone())
        .foreground(ColorSlot::Foreground);

    // Render with each theme
    let presets = [
        ("Dark", ThemePreset::Dark),
        ("Light", ThemePreset::Light),
        ("Dracula", ThemePreset::Dracula),
        ("Nord", ThemePreset::Nord),
        ("Catppuccin Mocha", ThemePreset::Catppuccin(CatppuccinFlavor::Mocha)),
    ];

    for (name, preset) in presets {
        ctx.set_preset(preset);

        println!("\n--- {} Theme ---", name);
        println!("{}", title.render("Hello, Themed World!"));
        println!("{}", body.render("The quick brown fox jumps over the lazy dog."));
    }
}
