//! Renders a preview of all built-in themes

use lipgloss::{Style, ThemePreset, ColorSlot, Theme};

fn main() {
    let presets = [
        ThemePreset::Dark,
        ThemePreset::Light,
        ThemePreset::Dracula,
        ThemePreset::Nord,
        ThemePreset::Catppuccin(CatppuccinFlavor::Mocha),
        ThemePreset::Catppuccin(CatppuccinFlavor::Latte),
        ThemePreset::TokyoNight,
        ThemePreset::Gruvbox(GruvboxVariant::Dark),
    ];

    for preset in presets {
        let theme = preset.to_theme();
        print_theme_preview(&theme);
        println!();
    }
}

fn print_theme_preview(theme: &Theme) {
    let name = theme.name().unwrap_or("Unknown");

    // Header
    let header = Style::from_theme(theme, ColorSlot::Primary)
        .bold(true);
    println!("{}", header.render(&format!("=== {} ===", name)));

    // Color swatches
    let slots = [
        (ColorSlot::Primary, "Primary"),
        (ColorSlot::Secondary, "Secondary"),
        (ColorSlot::Success, "Success"),
        (ColorSlot::Warning, "Warning"),
        (ColorSlot::Error, "Error"),
        (ColorSlot::Muted, "Muted"),
    ];

    for (slot, label) in slots {
        let style = Style::from_theme(theme, slot);
        println!("  {} {}", style.render("████"), label);
    }

    // Sample text
    let text = Style::from_theme(theme, ColorSlot::Foreground);
    println!("\n  {}", text.render("The quick brown fox jumps over the lazy dog."));
}
