//! Bubbletea TUI application with theme support

use bubbletea::{Program, Model, Cmd, Msg};
use lipgloss::{ThemedStyle, ThemeContext, ThemePreset, ColorSlot};
use std::sync::Arc;

struct App {
    theme_ctx: Arc<ThemeContext>,
    count: i32,
    styles: Styles,
}

struct Styles {
    title: ThemedStyle,
    counter: ThemedStyle,
    help: ThemedStyle,
}

impl App {
    fn new() -> Self {
        let theme_ctx = Arc::new(ThemeContext::from_preset(ThemePreset::Dracula));
        let styles = Styles::new(theme_ctx.clone());
        Self {
            theme_ctx,
            count: 0,
            styles,
        }
    }

    fn cycle_theme(&mut self) {
        let presets = [
            ThemePreset::Dracula,
            ThemePreset::Nord,
            ThemePreset::Catppuccin(CatppuccinFlavor::Mocha),
        ];
        // Cycle logic...
    }
}

impl Styles {
    fn new(ctx: Arc<ThemeContext>) -> Self {
        Self {
            title: ThemedStyle::new(ctx.clone())
                .foreground(ColorSlot::Primary)
                .bold(true),
            counter: ThemedStyle::new(ctx.clone())
                .foreground(ColorSlot::Secondary),
            help: ThemedStyle::new(ctx.clone())
                .foreground(ColorSlot::Muted)
                .italic(true),
        }
    }
}

impl Model for App {
    fn update(&mut self, msg: Msg) -> Cmd {
        match msg.downcast::<KeyMsg>() {
            Some(KeyMsg::Up) => self.count += 1,
            Some(KeyMsg::Down) => self.count -= 1,
            Some(KeyMsg::Tab) => self.cycle_theme(),
            Some(KeyMsg::Quit) => return Cmd::quit(),
            _ => {}
        }
        Cmd::none()
    }

    fn view(&self) -> String {
        format!(
            "{}\n\n{}\n\n{}",
            self.styles.title.render("Counter Demo"),
            self.styles.counter.render(&format!("Count: {}", self.count)),
            self.styles.help.render("↑/↓: change count | Tab: cycle theme | q: quit"),
        )
    }
}
